// ---- Clean Architecture Principles ----

// ---- Clean Architecture Layers ----
/*
┌─────────────────────────────────────────────────────┐
│                    Presentation Layer                │
│  (UI, ViewModels, Compose, Activities, Fragments)   │
│                      ↓                               │
│                    Domain Layer                      │
│  (Use Cases, Entities, Business Logic, Repository   │
│   Interfaces)                                       │
│                      ↓                               │
│                    Data Layer                        │
│  (Repository Implementation, Data Sources, Models)   │
└─────────────────────────────────────────────────────┘

Dependency Rule: Outer layers depend on inner layers.
Presentation → Domain ← Data
*/

// ---- Domain Layer - Entities ----
// Pure Kotlin classes, no Android dependencies

data class Player(
    val id: Int,
    val name: String,
    val health: Int,
    val attack: Int,
    val defense: Int,
    val level: Int
)

data class GameState(
    val players: List<Player>,
    val currentPlayer: Player?,
    val score: Int,
    val isGameOver: Boolean
)

// ---- Domain Layer - Repository Interface ----
interface PlayerRepository {
    suspend fun getPlayers(): List<Player>
    suspend fun getPlayer(id: Int): Player?
    suspend fun savePlayer(player: Player)
    suspend fun deletePlayer(id: Int)
    suspend fun updatePlayer(player: Player)
}

// ---- Domain Layer - Use Cases ----
class GetPlayersUseCase(
    private val repository: PlayerRepository
) {
    suspend operator fun invoke(): List<Player> {
        return repository.getPlayers()
    }
}

class GetPlayerUseCase(
    private val repository: PlayerRepository
) {
    suspend operator fun invoke(id: Int): Player? {
        return repository.getPlayer(id)
    }
}

class SavePlayerUseCase(
    private val repository: PlayerRepository
) {
    suspend operator fun invoke(player: Player) {
        repository.savePlayer(player)
    }
}

class DeletePlayerUseCase(
    private val repository: PlayerRepository
) {
    suspend operator fun invoke(id: Int) {
        repository.deletePlayer(id)
    }
}

// ---- Use Case with business logic ----
class LevelUpPlayerUseCase(
    private val repository: PlayerRepository
) {
    suspend operator fun invoke(id: Int): Player? {
        val player = repository.getPlayer(id) ?: return null
        val leveledPlayer = player.copy(
            level = player.level + 1,
            health = player.health + 20,
            attack = player.attack + 5,
            defense = player.defense + 3
        )
        repository.updatePlayer(leveledPlayer)
        return leveledPlayer
    }
}

class CalculateTeamScoreUseCase {
    operator fun invoke(players: List<Player>): Int {
        return players.sumOf { it.attack + it.defense + it.level * 10 }
    }
}

// ---- Presentation Layer - ViewModel ----
class CleanArchitectureViewModel(
    private val getPlayers: GetPlayersUseCase,
    private val getPlayer: GetPlayerUseCase,
    private val savePlayer: SavePlayerUseCase,
    private val deletePlayer: DeletePlayerUseCase,
    private val levelUpPlayer: LevelUpPlayerUseCase,
    private val calculateScore: CalculateTeamScoreUseCase
) : ViewModel() {

    data class UiState(
        val players: List<Player> = emptyList(),
        val selectedPlayer: Player? = null,
        val teamScore: Int = 0,
        val isLoading: Boolean = false,
        val error: String? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    fun loadPlayers() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                val players = getPlayers()
                val score = calculateScore(players)
                _uiState.update {
                    it.copy(
                        players = players,
                        teamScore = score,
                        isLoading = false
                    )
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun selectPlayer(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val player = getPlayer(id)
                _uiState.update {
                    it.copy(selectedPlayer = player, isLoading = false)
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun levelUp(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val leveled = levelUpPlayer(id)
                if (leveled != null) {
                    _uiState.update {
                        it.copy(
                            selectedPlayer = leveled,
                            isLoading = false
                        )
                    }
                    loadPlayers() // Refresh list
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun deletePlayer(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                deletePlayer(id)
                _uiState.update {
                    it.copy(
                        selectedPlayer = null,
                        isLoading = false
                    )
                }
                loadPlayers()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

// ---- Data Layer - Repository Implementation ----
class PlayerRepositoryImpl(
    private val localDataSource: PlayerLocalDataSource
) : PlayerRepository {
    override suspend fun getPlayers(): List<Player> {
        return localDataSource.getPlayers()
    }

    override suspend fun getPlayer(id: Int): Player? {
        return localDataSource.getPlayer(id)
    }

    override suspend fun savePlayer(player: Player) {
        localDataSource.savePlayer(player)
    }

    override suspend fun deletePlayer(id: Int) {
        localDataSource.deletePlayer(id)
    }

    override suspend fun updatePlayer(player: Player) {
        localDataSource.updatePlayer(player)
    }
}

// ---- Data Layer - Data Source Interface ----
interface PlayerLocalDataSource {
    suspend fun getPlayers(): List<Player>
    suspend fun getPlayer(id: Int): Player?
    suspend fun savePlayer(player: Player)
    suspend fun deletePlayer(id: Int)
    suspend fun updatePlayer(player: Player)
}

// ---- Data Layer - Room Implementation ----
class PlayerRoomDataSource(
    private val dao: PlayerDao
) : PlayerLocalDataSource {
    override suspend fun getPlayers(): List<Player> {
        return dao.getAllPlayers().map { it.toDomain() }
    }

    override suspend fun getPlayer(id: Int): Player? {
        return dao.getPlayerById(id)?.toDomain()
    }

    override suspend fun savePlayer(player: Player) {
        dao.insertPlayer(player.toEntity())
    }

    override suspend fun deletePlayer(id: Int) {
        dao.deletePlayerById(id)
    }

    override suspend fun updatePlayer(player: Player) {
        dao.updatePlayer(player.toEntity())
    }
}

// ---- Mapping extensions ----
fun Player.toEntity(): PlayerEntity {
    return PlayerEntity(
        id = id,
        name = name,
        health = health,
        attack = attack,
        defense = defense,
        level = level
    )
}

fun PlayerEntity.toDomain(): Player {
    return Player(
        id = id,
        name = name,
        health = health,
        attack = attack,
        defense = defense,
        level = level
    )
}

